package store

import (
	"context"
	"database/sql"
	"encoding/json"
	"path/filepath"
	"testing"

	_ "modernc.org/sqlite"
)

// TestMigrate_v2ToV3_RebuildsFTS pins the FTS-hash regression fix: when an
// existing v2 database is opened by a binary built from press ≥4.18.1, the
// migration must drop and rebuild resources_fts so leftover polynomial-hash
// rowids don't co-exist with new FNV-64a rowids. Without the rebuild, search
// returns duplicate rows on every hit and the second-insert path tries to
// write into a table that still contains the pre-hash entries.
func TestMigrate_v2ToV3_RebuildsFTS(t *testing.T) {
	t.Parallel()

	dbPath := filepath.Join(t.TempDir(), "tenderned.db")
	resource := "notices"
	itemBytes := json.RawMessage(`{"id":"t-1","title":"hello world"}`)

	// Stage 1: fresh DB, sync one row, then downgrade user_version to 2 and
	// inject a ghost FTS row at a bogus rowid — simulating the leftover that
	// the polynomial-hash code would have written before the FNV switch.
	{
		s, err := Open(dbPath)
		if err != nil {
			t.Fatalf("Open initial: %v", err)
		}
		if _, _, err := s.UpsertBatch(resource, []json.RawMessage{itemBytes}); err != nil {
			s.Close()
			t.Fatalf("UpsertBatch: %v", err)
		}
		s.Close()
	}

	{
		raw, err := sql.Open("sqlite", "file:"+dbPath)
		if err != nil {
			t.Fatalf("raw open: %v", err)
		}
		if _, err := raw.ExecContext(context.Background(), "PRAGMA user_version = 2"); err != nil {
			raw.Close()
			t.Fatalf("downgrade user_version: %v", err)
		}
		if _, err := raw.ExecContext(context.Background(),
			"INSERT INTO resources_fts(rowid, id, resource_type, content) VALUES (?, ?, ?, ?)",
			9999999999, "t-1", resource, "ghost content"); err != nil {
			raw.Close()
			t.Fatalf("inject ghost row: %v", err)
		}
		raw.Close()
	}

	// Stage 2: reopen via Open — triggers the v2→v3 migration path which
	// must rehash resources_fts via drop + rebuild.
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("Open after downgrade: %v", err)
	}
	defer s.Close()

	var version int
	if err := s.db.QueryRowContext(context.Background(), "PRAGMA user_version").Scan(&version); err != nil {
		t.Fatalf("read user_version: %v", err)
	}
	if version != StoreSchemaVersion {
		t.Errorf("user_version after migrate = %d, want %d", version, StoreSchemaVersion)
	}

	var ftsCount int
	if err := s.db.QueryRowContext(context.Background(),
		"SELECT COUNT(*) FROM resources_fts WHERE resource_type = ?", resource).Scan(&ftsCount); err != nil {
		t.Fatalf("count fts rows: %v", err)
	}
	if ftsCount != 1 {
		t.Errorf("resources_fts rows = %d, want 1 (the ghost should have been dropped during v2→v3 migration; finding 2 means the rebuild didn't run, 0 means the rebuild didn't repopulate from resources)", ftsCount)
	}

	// And the surviving row's rowid must match the current ftsRowID — the
	// new FNV-64a value, not the bogus ghost rowid we injected.
	expectedRowid := ftsRowID(resource, "t-1")
	var actualRowid int64
	if err := s.db.QueryRowContext(context.Background(),
		"SELECT rowid FROM resources_fts WHERE resource_type = ? LIMIT 1", resource).Scan(&actualRowid); err != nil {
		t.Fatalf("read fts rowid: %v", err)
	}
	if actualRowid != expectedRowid {
		t.Errorf("resources_fts.rowid = %d, want %d (the rebuild should have written rows at the current FNV-64a rowid)", actualRowid, expectedRowid)
	}
}
